/* LabOS complete production automation

Broker: labos:1883
Vision inputs: lab/vision/#, lab/people/#, lab/lab101/occupancy/#
ESP inputs: lab/control/status and lab/control/relay+/state
Control: lab/automation/mode = auto | manual

Rules:
  1 person   -> both lights
  2-3 people -> both lights + Fan 1 + Fan 4
  4+ people  -> both lights + all fans
  0 people continuously for 5 minutes -> everything OFF

Invalid/stale/lost vision data preserves the previous relay state.
Relay commands are retained. Three matching readings prevent flicker.
*/
const STABLE_READINGS=3, EMPTY_DELAY_MS=300000, VISION_STALE_MS=30000, MIN_CHANGE_MS=8000;
const topics={spare1:'lab/control/relay1/set',light2:'lab/control/relay2/set',fan1:'lab/control/relay3/set',fan3:'lab/control/relay4/set',spare5:'lab/control/relay5/set',fan4:'lab/control/relay6/set',light1:'lab/control/relay7/set',fan2:'lab/control/relay8/set'};
const stateTopics={1:'spare1',2:'light2',3:'fan1',4:'fan3',5:'spare5',6:'fan4',7:'light1',8:'fan2'};
function pub(topic,payload,retain=true){return {topic,payload:String(payload),retain};}
function emit(items){if(items.length) node.send([items]);}
function states(mode){let s={spare1:'OFF',light2:'OFF',fan1:'OFF',fan3:'OFF',spare5:'OFF',fan4:'OFF',light1:'OFF',fan2:'OFF'};if(mode==='ONE'){s.light1='ON';s.light2='ON';}else if(mode==='TWO_THREE'){s.light1='ON';s.light2='ON';s.fan1='ON';s.fan4='ON';}else if(mode==='FOUR_PLUS'){s.light1='ON';s.light2='ON';s.fan1='ON';s.fan2='ON';s.fan3='ON';s.fan4='ON';}return s;}
function modeFor(n){return n<=0?'EMPTY':n===1?'ONE':n<4?'TWO_THREE':'FOUR_PLUS';}
function apply(mode,count,reason){const desired=states(mode),out=[];for(const [d,t] of Object.entries(topics))out.push(pub(t,desired[d]));out.push(pub('lab/automation/active_stage',mode));out.push(pub('lab/automation/people_count',count));out.push(pub('lab/automation/last_action',reason));context.set('desired',desired);context.set('activeStage',mode);context.set('lastApply',Date.now());context.set('pendingStage','');context.set('stable',0);emit(out);node.status({fill:mode==='EMPTY'?'red':'green',shape:'dot',text:mode+' count='+count});}
function parseCount(payload){if(Buffer.isBuffer(payload))payload=payload.toString();if(typeof payload==='number')return Number.isFinite(payload)?payload:null;let x=String(payload??'').trim();if(!x)return null;if(x.startsWith('{')){try{const o=JSON.parse(x);for(const k of ['people_count','person_count','count','persons','occupancy','stable_count'])if(o[k]!==undefined&&Number.isFinite(Number(o[k])))return Number(o[k]);return null;}catch(e){return null;}}const n=Number(x);return Number.isFinite(n)?n:null;}
function isVision(t){return t.startsWith('lab/vision/')||t.startsWith('lab/people/')||t.startsWith('lab/lab101/occupancy/');}
const t=String(msg.topic||''), now=Date.now();let out=[];
if(t==='lab/automation/mode'){const m=String(msg.payload).toLowerCase();if(m==='auto'||m==='manual'){context.set('automationMode',m);out.push(pub('lab/automation/mode_state',m));out.push(pub('lab/automation/last_action','Mode changed to '+m));emit(out);node.status({fill:m==='auto'?'green':'blue',shape:'ring',text:m+' mode'});}return null;}
if(t==='lab/control/status'){const status=String(msg.payload).toLowerCase();context.set('relayOnline',status==='online');emit([pub('lab/automation/relay_health',status)]);return null;}
const sm=t.match(/^lab\/control\/relay(\d+)\/state$/);if(sm){const relay=Number(sm[1]),actual=String(msg.payload).toUpperCase(),actuals=context.get('actual')||{};actuals[relay]=actual;context.set('actual',actuals);const desired=context.get('desired'),device=stateTopics[relay];if(desired&&device&&desired[device]!==actual){out.push(pub('lab/automation/warning','Relay '+relay+' mismatch: expected '+desired[device]+' got '+actual));}emit(out);return null;}
if(t==='lab/automation/tick'){const last=context.get('lastVision')||0,age=last?Math.floor((now-last)/1000):-1,health=last&&now-last<=VISION_STALE_MS?'healthy':'stale';out.push(pub('lab/automation/vision_health',health));out.push(pub('lab/automation/vision_age_seconds',age));out.push(pub('lab/automation/relay_health',context.get('relayOnline')?'online':'offline'));if(health==='stale')out.push(pub('lab/automation/warning','Vision stale; previous relay state preserved'));emit(out);return null;}
if(!isVision(t))return null;
// Vision status messages are health-only and never interpreted as a count.
if(t.endsWith('/status')||t.endsWith('/source_status')){const h=String(msg.payload).toLowerCase();emit([pub('lab/automation/vision_health',(h.includes('online')||h.includes('healthy'))?'healthy':'unhealthy')]);return null;}
const countRaw=parseCount(msg.payload);if(countRaw===null||Number.isNaN(countRaw)){emit([pub('lab/automation/warning','Invalid vision payload ignored; previous relay state preserved')]);return null;}
const count=Math.max(0,Math.floor(countRaw));context.set('lastVision',now);out.push(pub('lab/vision/people_count/state',count));out.push(pub('lab/automation/vision_health','healthy'));emit(out);
if((context.get('automationMode')||'manual')!=='auto'){node.status({fill:'blue',shape:'ring',text:'manual; count='+count});return null;}
let emptyTimer=context.get('emptyTimer');if(count>0&&emptyTimer){clearTimeout(emptyTimer);context.set('emptyTimer',null);emptyTimer=null;}
const target=modeFor(count),active=context.get('activeStage')||'UNKNOWN';if(target===active){context.set('pendingStage','');context.set('stable',0);return null;}
let pending=context.get('pendingStage')||'',stable=context.get('stable')||0;if(target===pending)stable++;else{pending=target;stable=1;}context.set('pendingStage',pending);context.set('stable',stable);if(stable<STABLE_READINGS){node.status({fill:'yellow',shape:'ring',text:'checking '+target+' '+stable+'/'+STABLE_READINGS});return null;}
if(target==='EMPTY'){if(!emptyTimer){const source=t;emptyTimer=setTimeout(()=>{context.set('emptyTimer',null);if((context.get('automationMode')||'manual')==='auto')apply('EMPTY',0,'No people continuously detected for 5 minutes');},EMPTY_DELAY_MS);context.set('emptyTimer',emptyTimer);}node.status({fill:'yellow',shape:'ring',text:'empty; OFF in 5 minutes'});return null;}
if(now-(context.get('lastApply')||0)<MIN_CHANGE_MS)return null;apply(target,count,'Applied occupancy stage '+target);return null;
